package com.enterprise.samlsp.model;

import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;

import java.util.*;

public class SamlAuthenticatedUser implements UserDetails {
    private static final long serialVersionUID = 1L;

    private String nameId;
    private String email;
    private String firstName;
    private String lastName;
    private String displayName;
    private String department;
    private List<String> groups;
    private Map<String, SamlUserAttribute> allAttributes;
    private String sessionIndex;
    private Set<GrantedAuthority> authorities;

    public SamlAuthenticatedUser(SamlAssertion assertion) {
        this.nameId = assertion.getNameId();
        this.sessionIndex = assertion.getSessionIndex();
        this.allAttributes = new HashMap<>(assertion.getAttributes());

        this.email = resolveAttribute(assertion, "email",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress",
                "urn:oid:0.9.2342.19200300.100.1.3");
        this.firstName = resolveAttribute(assertion, "firstName",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname",
                "urn:oid:2.5.4.42");
        this.lastName = resolveAttribute(assertion, "lastName",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname",
                "urn:oid:2.5.4.4");
        this.displayName = resolveAttribute(assertion, "displayName",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name",
                "urn:oid:2.16.840.1.113730.3.1.241");
        this.department = resolveAttribute(assertion, "department",
                "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/department");

        this.groups = new ArrayList<>();
        List<String> groupValues = resolveAttributeValues(assertion, "groups",
                "http://schemas.xmlsoap.org/claims/Group",
                "memberOf");
        if (groupValues != null) {
            this.groups.addAll(groupValues);
        }

        this.authorities = new HashSet<>();
        this.authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
        if (this.groups != null) {
            for (String group : this.groups) {
                this.authorities.add(new SimpleGrantedAuthority("ROLE_" + group.toUpperCase().replace(" ", "_")));
            }
        }

        if (this.displayName == null && this.firstName != null && this.lastName != null) {
            this.displayName = this.firstName + " " + this.lastName;
        }
    }

    private String resolveAttribute(SamlAssertion assertion, String... names) {
        for (String name : names) {
            String value = assertion.getAttributeValue(name);
            if (value != null) return value;
        }
        return null;
    }

    private List<String> resolveAttributeValues(SamlAssertion assertion, String... names) {
        for (String name : names) {
            List<String> values = assertion.getAttributeValues(name);
            if (values != null && !values.isEmpty()) return values;
        }
        return null;
    }

    @Override
    public Collection<? extends GrantedAuthority> getAuthorities() { return authorities; }
    @Override
    public String getPassword() { return null; }
    @Override
    public String getUsername() { return nameId; }
    @Override
    public boolean isAccountNonExpired() { return true; }
    @Override
    public boolean isAccountNonLocked() { return true; }
    @Override
    public boolean isCredentialsNonExpired() { return true; }
    @Override
    public boolean isEnabled() { return true; }

    public String getNameId() { return nameId; }
    public String getEmail() { return email; }
    public String getFirstName() { return firstName; }
    public String getLastName() { return lastName; }
    public String getDisplayName() { return displayName; }
    public String getDepartment() { return department; }
    public List<String> getGroups() { return groups; }
    public Map<String, SamlUserAttribute> getAllAttributes() { return allAttributes; }
    public String getSessionIndex() { return sessionIndex; }
}

